// ============================================================
// Security: Cleartext Traffic Prevention
// ============================================================

/**
 * Validates whether a URL is allowed based on security policy.
 * - HTTPS is always allowed.
 * - HTTP (cleartext) is ONLY allowed for whitelisted local IoT device IPs.
 * - All other HTTP requests are blocked to prevent insecure cleartext traffic.
 */
function validateUrlSecurity(url) {
  const parsedUrl = new URL(url);
  const protocol = parsedUrl.protocol;
  const hostname = parsedUrl.hostname;

  // HTTPS is always allowed
  if (protocol === 'https:') {
    return { allowed: true, reason: 'HTTPS connection' };
  }

  // HTTP (cleartext) - only allow for local IoT devices
  if (protocol === 'http:') {
    const isLocalIoT = ALLOWED_IOT_SUBNETS.some((regex) => regex.test(hostname));

    if (isLocalIoT) {
      return {
        allowed: true,
        reason: `Cleartext HTTP allowed for local IoT device: ${hostname}`,
      };
    }

    return {
      allowed: false,
      reason: `BLOCKED: Insecure cleartext HTTP traffic to non-local host "${hostname}". Use HTTPS instead.`,
    };
  }

  return {
    allowed: false,
    reason: `BLOCKED: Unsupported protocol "${protocol}"`,
  };
}

// ============================================================
// Timeout wrapper for fetch
// ============================================================

function fetchWithTimeout(url, options = {}, timeout = DEFAULT_TIMEOUT) {
  const controller = new AbortController();
  const { signal } = controller;

  const timeoutId = setTimeout(() => {
    controller.abort();
  }, timeout);

  return fetch(url, { ...options, signal })
    .then((response) => {
      clearTimeout(timeoutId);
      return response;
    })
    .catch((error) => {
      clearTimeout(timeoutId);
      if (error.name === 'AbortError') {
        throw new NetworkError(`Request timed out after ${timeout}ms`, 'TIMEOUT', url);
      }
      throw error;
    });
}

// ============================================================
// Custom Error Classes
// ============================================================

class NetworkError extends Error {
  constructor(message, code, url, statusCode = null, responseBody = null) {
    super(message);
    this.name = 'NetworkError';
    this.code = code;
    this.url = url;
    this.statusCode = statusCode;
    this.responseBody = responseBody;
  }
}

class CleartextBlockedError extends Error {
  constructor(url, reason) {
    super(`Cleartext traffic blocked: ${reason}`);
    this.name = 'CleartextBlockedError';
    this.url = url;
    this.reason = reason;
  }
}

