async function refreshAuthToken() {
  if (_isRefreshing) {
    // Queue the request and wait for the refresh to complete
    return new Promise((resolve, reject) => {
      _refreshQueue.push({ resolve, reject });
    });
  }

  _isRefreshing = true;

  try {
    if (!_refreshToken) {
      throw new NetworkError('No refresh token available', 'AUTH_ERROR');
    }

    const response = await fetchWithTimeout(
      `${API_BASE_URL}/auth/refresh`,
      {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ refreshToken: _refreshToken }),
      },
      DEFAULT_TIMEOUT
    );

    if (!response.ok) {
      throw new NetworkError('Token refresh failed', 'AUTH_ERROR', null, response.status);
    }

    const data = await response.json();
    _authToken = data.accessToken;
    _refreshToken = data.refreshToken || _refreshToken;

    if (_tokenRefreshCallback) {
      _tokenRefreshCallback(data);
    }

    // Resolve all queued requests
    _refreshQueue.forEach(({ resolve }) => resolve(_authToken));
    _refreshQueue = [];

    return _authToken;
  } catch (error) {
    _refreshQueue.forEach(({ reject }) => reject(error));
    _refreshQueue = [];
    throw error;
  } finally {
    _isRefreshing = false;
  }
}

