// ============================================================
// IoT Device Client (HTTP allowed for local network only)
// ============================================================

class IoTDeviceClient {
  constructor(deviceIp, port = 80) {
    // Validate that the IP is in allowed local range
    const isAllowed = ALLOWED_IOT_SUBNETS.some((regex) => regex.test(deviceIp));
    if (!isAllowed) {
      throw new Error(
        `IoT device IP "${deviceIp}" is not in an allowed local subnet. ` +
        'Only private network IPs (192.168.x.x, 10.x.x.x, 172.16-31.x.x) are permitted.'
      );
    }

    this.deviceIp = deviceIp;
    this.port = port;
    // Use HTTPS if available, fall back to HTTP for legacy devices
    this.useHttps = false; // Default to HTTP for legacy IoT devices
    this.baseUrl = this._buildBaseUrl();
  }

  _buildBaseUrl() {
    const protocol = this.useHttps ? 'https' : 'http';
    return `${protocol}://${this.deviceIp}:${this.port}`;
  }

  /**
   * Enable HTTPS for devices that support it
   */
  enableHttps(enable = true) {
    this.useHttps = enable;
    this.baseUrl = this._buildBaseUrl();
    return this;
  }

  /**
   * Probe the device to check if it's reachable
   */
  async ping(timeoutMs = 3000) {
    try {
      const result = await request(`${this.baseUrl}/`, {
        method: 'GET',
        timeout: timeoutMs,
      });
      return { reachable: true, status: result.status };
    } catch (error) {
      return { reachable: false, error: error.message };
    }
  }

  /**
   * Try HTTPS first, fall back to HTTP if HTTPS fails
   */
  async autoDetectProtocol(timeoutMs = 3000) {
    // Try HTTPS first
    try {
      const httpsUrl = `https://${this.deviceIp}:${this.port}/`;
      const securityCheck = validateUrlSecurity(httpsUrl);
      if (securityCheck.allowed) {
        await fetchWithTimeout(httpsUrl, { method: 'HEAD' }, timeoutMs);
        this.useHttps = true;
        this.baseUrl = this._buildBaseUrl();
        if (__DEV__) {
          console.log(`[IoT] Device ${this.deviceIp} supports HTTPS`);
        }
        return 'https';
      }
    } catch (e) {
      // HTTPS not available, fall back to HTTP
    }

    // Fall back to HTTP (allowed for local IoT devices)
    this.useHttps = false;
    this.baseUrl = this._buildBaseUrl();
    if (__DEV__) {
      console.log(`[IoT] Device ${this.deviceIp} using HTTP (legacy device)`);
    }
    return 'http';
  }

  get(path, options = {}) {
    return request(`${this.baseUrl}${path}`, {
      method: 'GET',
      timeout: IOT_TIMEOUT,
      skipAuth: true, // IoT devices don't use our API auth
      ...options,
    });
  }

  post(path, body = {}, options = {}) {
    return request(`${this.baseUrl}${path}`, {
      method: 'POST',
      body,
      timeout: IOT_TIMEOUT,
      skipAuth: true,
      ...options,
    });
  }

  put(path, body = {}, options = {}) {
    return request(`${this.baseUrl}${path}`, {
      method: 'PUT',
      body,
      timeout: IOT_TIMEOUT,
      skipAuth: true,
      ...options,
    });
  }

  delete(path, options = {}) {
    return request(`${this.baseUrl}${path}`, {
      method: 'DELETE',
      timeout: IOT_TIMEOUT,
      skipAuth: true,
      ...options,
    });
  }

  /**
   * Send a command to the IoT device
   */
  async sendCommand(command, params = {}) {
    return this.post('/api/command', {
      command,
      params,
      timestamp: Date.now(),
    });
  }

  /**
   * Get device status/info
   */
  async getStatus() {
    return this.get('/api/status');
  }

  /**
   * Get device sensor data
   */
  async getSensorData() {
    return this.get('/api/sensors');
  }

  /**
   * Update device firmware or configuration
   */
  async updateConfig(config) {
    return this.put('/api/config', config);
  }
}

// ============================================================
// IoT Device Discovery / Manager
// ============================================================

class IoTDeviceManager {
  constructor() {
    this.devices = new Map();
  }

  /**
   * Register a known IoT device
   */
  registerDevice(id, ip, port = 80, metadata = {}) {
    const client = new IoTDeviceClient(ip, port);
    this.devices.set(id, {
      client,
      ip,
      port,
      metadata,
      lastSeen: null,
      online: false,
    });
    return client;
  }

  /**
   * Get a registered device client
   */
  getDevice(id) {
    const device = this.devices.get(id);
    if (!device) {
      throw new Error(`IoT device "${id}" not registered`);
    }
    return device.client;
  }

  /**
   * Remove a registered device
   */
  removeDevice(id) {
    return this.devices.delete(id);
  }

  /**
   * Scan a subnet for IoT devices
   */
  async scanSubnet(subnet = '192.168.1', startIp = 1, endIp = 254, port = 80, timeoutMs = 1000) {
    const discoveredDevices = [];
    const scanPromises = [];

    for (let i = startIp; i <= endIp; i++) {
      const ip = `${subnet}.${i}`;
      const scanPromise = (async () => {
        try {
          const client = new IoTDeviceClient(ip, port);
          const pingResult = await client.ping(timeoutMs);
          if (pingResult.reachable) {
            discoveredDevices.push({
              ip,
              port,
              status: pingResult.status,
            });
          }
        } catch (e) {
          // Device not reachable, skip
        }
      })();
      scanPromises.push(scanPromise);
    }

    // Run scans in batches to avoid overwhelming the network
    const batchSize = 20;
    for (let i = 0; i < scanPromises.length; i += batchSize) {
      await Promise.all(scanPromises.slice(i, i + batchSize));
    }

    return discoveredDevices;
  }

  /**
   * Check online status of all registered devices
   */
  async checkAllDevices() {
    const results = {};

    const checks = Array.from(this.devices.entries()).map(async ([id, device]) => {
      const pingResult = await device.client.ping();
      device.online = pingResult.reachable;
      device.lastSeen = pingResult.reachable ? new Date() : device.lastSeen;
      results[id] = {
        online: pingResult.reachable,
        lastSeen: device.lastSeen,
        ip: device.ip,
      };
    });

    await Promise.all(checks);
    return results;
  }

  /**
   * Get all registered devices and their status
   */
  getAllDevices() {
    const deviceList = {};
    this.devices.forEach((device, id) => {
      deviceList[id] = {
        ip: device.ip,
        port: device.port,
        online: device.online,
        lastSeen: device.lastSeen,
        metadata: device.metadata,
      };
    });
    return deviceList;
  }
}

